// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{})
}

// ServeMux is an abstraction of http.ServeMux.
type ServeMux interface {
	HandleFunc(pattern string, handler func(http.ResponseWriter, *http.Request))
	ServeHTTP(w http.ResponseWriter, r *http.Request)
}

type StdHTTPServerOptions struct {
	BaseURL          string
	BaseRouter       ServeMux
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, m ServeMux) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseRouter: m,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc("POST "+options.BaseURL+"/faucet", wrapper.Faucet)
	m.HandleFunc("POST "+options.BaseURL+"/players", wrapper.CreatePlayerData)
	m.HandleFunc("GET "+options.BaseURL+"/players/lookup/{platform}/{platformId}", wrapper.LookupPlayerDataBySocial)
	m.HandleFunc("GET "+options.BaseURL+"/players/rlookup/{platform}/{playerId}", wrapper.LookupSocialByPlayerId)
	m.HandleFunc("POST "+options.BaseURL+"/players/verify/attempt", wrapper.AttemptVerification)
	m.HandleFunc("POST "+options.BaseURL+"/players/verify/discord", wrapper.BeginVerifyDiscord)
	m.HandleFunc("GET "+options.BaseURL+"/players/{idOrUsername}/id", wrapper.GetPlayerId)
	m.HandleFunc("GET "+options.BaseURL+"/players/{playerId}", wrapper.GetPlayerData)
	m.HandleFunc("PATCH "+options.BaseURL+"/players/{playerId}", wrapper.UpdatePlayerData)
	m.HandleFunc("GET "+options.BaseURL+"/players/{playerId}/alts", wrapper.GetPlayerAlts)
	m.HandleFunc("POST "+options.BaseURL+"/players/{playerId}/api", wrapper.CyclePlayerApiKey)
	m.HandleFunc("GET "+options.BaseURL+"/players/{playerId}/backpack", wrapper.GetPlayerBackpack)
	m.HandleFunc("POST "+options.BaseURL+"/players/{playerId}/backpack", wrapper.GivePlayerItems)
	m.HandleFunc("GET "+options.BaseURL+"/players/{playerId}/blocks", wrapper.GetBlockedPlayers)
	m.HandleFunc("POST "+options.BaseURL+"/players/{playerId}/blocks", wrapper.BlockPlayer)
	m.HandleFunc("DELETE "+options.BaseURL+"/players/{playerId}/blocks/{targetId}", wrapper.UnblockPlayer)
	m.HandleFunc("GET "+options.BaseURL+"/players/{playerId}/cosmetics", wrapper.GetPlayerCosmetics)
	m.HandleFunc("POST "+options.BaseURL+"/players/{playerId}/cosmetics", wrapper.BuyCosmetic)
	m.HandleFunc("GET "+options.BaseURL+"/players/{playerId}/displayname", wrapper.GetPlayerDisplayNameV2)
	m.HandleFunc("GET "+options.BaseURL+"/players/{playerId}/friends", wrapper.GetPlayerFriends)
	m.HandleFunc("GET "+options.BaseURL+"/players/{playerId}/friends/requests", wrapper.GetFriendRequests)
	m.HandleFunc("POST "+options.BaseURL+"/players/{playerId}/friends/requests", wrapper.SendFriendRequest)
	m.HandleFunc("DELETE "+options.BaseURL+"/players/{playerId}/friends/requests/{targetId}", wrapper.DeleteFriendRequest)
	m.HandleFunc("POST "+options.BaseURL+"/players/{playerId}/friends/requests/{targetId}/accept", wrapper.AcceptFriendRequest)
	m.HandleFunc("DELETE "+options.BaseURL+"/players/{playerId}/friends/{targetId}", wrapper.RemoveFriend)
	m.HandleFunc("GET "+options.BaseURL+"/players/{playerId}/hypercube", wrapper.GetPlayerHypercube)
	m.HandleFunc("DELETE "+options.BaseURL+"/players/{playerId}/totp", wrapper.RemoveTotp)
	m.HandleFunc("GET "+options.BaseURL+"/players/{playerId}/totp", wrapper.CheckTotp)
	m.HandleFunc("PATCH "+options.BaseURL+"/players/{playerId}/totp/setup", wrapper.CompleteTotpSetup)
	m.HandleFunc("POST "+options.BaseURL+"/players/{playerId}/totp/setup", wrapper.BeginTotpSetup)
	m.HandleFunc("POST "+options.BaseURL+"/players/{playerId}/upgrades", wrapper.BuyNamedUpgrade)
	m.HandleFunc("GET "+options.BaseURL+"/punishments", wrapper.GetPunishments)
	m.HandleFunc("POST "+options.BaseURL+"/punishments", wrapper.CreatePunishment)
	m.HandleFunc("GET "+options.BaseURL+"/punishments/ladders", wrapper.GetPunishmentLadders)
	m.HandleFunc("GET "+options.BaseURL+"/punishments/ladders/entry", wrapper.GetPunishmentLadderEntry)
	m.HandleFunc("POST "+options.BaseURL+"/punishments/revoke", wrapper.RevokePunishment)
	m.HandleFunc("GET "+options.BaseURL+"/punishments/{playerId}/active", wrapper.GetActivePunishment)
	m.HandleFunc("GET "+options.BaseURL+"/recap/{playerId}/{year}", wrapper.GetPlayerRecap)
	m.HandleFunc("POST "+options.BaseURL+"/tab_complete", wrapper.PerformTabComplete)
	m.HandleFunc("POST "+options.BaseURL+"/tebex/checkout", wrapper.TebexCheckout)

	return m
}

