// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Endpoint to give players currency
	// (POST /faucet)
	Faucet(ctx context.Context, request FaucetRequestObject) (FaucetResponseObject, error)
	// Create new player data
	// (POST /players)
	CreatePlayerData(ctx context.Context, request CreatePlayerDataRequestObject) (CreatePlayerDataResponseObject, error)
	// Lookup player data by social
	// (GET /players/lookup/{platform}/{platformId})
	LookupPlayerDataBySocial(ctx context.Context, request LookupPlayerDataBySocialRequestObject) (LookupPlayerDataBySocialResponseObject, error)
	// Lookup social id by player id
	// (GET /players/rlookup/{platform}/{playerId})
	LookupSocialByPlayerId(ctx context.Context, request LookupSocialByPlayerIdRequestObject) (LookupSocialByPlayerIdResponseObject, error)
	// Attempt to verify a player's account
	// (POST /players/verify/attempt)
	AttemptVerification(ctx context.Context, request AttemptVerificationRequestObject) (AttemptVerificationResponseObject, error)
	// Begin Discord account verification
	// (POST /players/verify/discord)
	BeginVerifyDiscord(ctx context.Context, request BeginVerifyDiscordRequestObject) (BeginVerifyDiscordResponseObject, error)
	// Get the player ID for a player
	// (GET /players/{idOrUsername}/id)
	GetPlayerId(ctx context.Context, request GetPlayerIdRequestObject) (GetPlayerIdResponseObject, error)
	// Get player data
	// (GET /players/{playerId})
	GetPlayerData(ctx context.Context, request GetPlayerDataRequestObject) (GetPlayerDataResponseObject, error)
	// Update player data
	// (PATCH /players/{playerId})
	UpdatePlayerData(ctx context.Context, request UpdatePlayerDataRequestObject) (UpdatePlayerDataResponseObject, error)
	// Get the (ip-based) alt accounts for a player
	// (GET /players/{playerId}/alts)
	GetPlayerAlts(ctx context.Context, request GetPlayerAltsRequestObject) (GetPlayerAltsResponseObject, error)
	// Cycle the API key for a player. Deletes all active keys and creates a new one
	// (POST /players/{playerId}/api)
	CyclePlayerApiKey(ctx context.Context, request CyclePlayerApiKeyRequestObject) (CyclePlayerApiKeyResponseObject, error)
	// Get the backpack for a player
	// (GET /players/{playerId}/backpack)
	GetPlayerBackpack(ctx context.Context, request GetPlayerBackpackRequestObject) (GetPlayerBackpackResponseObject, error)
	// Give a player items/currencies
	// (POST /players/{playerId}/backpack)
	GivePlayerItems(ctx context.Context, request GivePlayerItemsRequestObject) (GivePlayerItemsResponseObject, error)
	// Get players blocked by this player
	// (GET /players/{playerId}/blocks)
	GetBlockedPlayers(ctx context.Context, request GetBlockedPlayersRequestObject) (GetBlockedPlayersResponseObject, error)
	// Block a player
	// (POST /players/{playerId}/blocks)
	BlockPlayer(ctx context.Context, request BlockPlayerRequestObject) (BlockPlayerResponseObject, error)
	// Unblock a player
	// (DELETE /players/{playerId}/blocks/{targetId})
	UnblockPlayer(ctx context.Context, request UnblockPlayerRequestObject) (UnblockPlayerResponseObject, error)
	// Fetch all unlocked cosmetics for the given player
	// (GET /players/{playerId}/cosmetics)
	GetPlayerCosmetics(ctx context.Context, request GetPlayerCosmeticsRequestObject) (GetPlayerCosmeticsResponseObject, error)
	// Buy a cosmetic for the provided price
	// (POST /players/{playerId}/cosmetics)
	BuyCosmetic(ctx context.Context, request BuyCosmeticRequestObject) (BuyCosmeticResponseObject, error)
	// Get the display name for a player
	// (GET /players/{playerId}/displayname)
	GetPlayerDisplayNameV2(ctx context.Context, request GetPlayerDisplayNameV2RequestObject) (GetPlayerDisplayNameV2ResponseObject, error)
	// Get a player's friends
	// (GET /players/{playerId}/friends)
	GetPlayerFriends(ctx context.Context, request GetPlayerFriendsRequestObject) (GetPlayerFriendsResponseObject, error)
	// Get a player's friend requests
	// (GET /players/{playerId}/friends/requests)
	GetFriendRequests(ctx context.Context, request GetFriendRequestsRequestObject) (GetFriendRequestsResponseObject, error)
	// Send a friend request to another player
	// (POST /players/{playerId}/friends/requests)
	SendFriendRequest(ctx context.Context, request SendFriendRequestRequestObject) (SendFriendRequestResponseObject, error)
	// Delete a friend request (cancel outgoing or decline incoming)
	// (DELETE /players/{playerId}/friends/requests/{targetId})
	DeleteFriendRequest(ctx context.Context, request DeleteFriendRequestRequestObject) (DeleteFriendRequestResponseObject, error)
	// Accept an incoming friend request
	// (POST /players/{playerId}/friends/requests/{targetId}/accept)
	AcceptFriendRequest(ctx context.Context, request AcceptFriendRequestRequestObject) (AcceptFriendRequestResponseObject, error)
	// Remove a friend
	// (DELETE /players/{playerId}/friends/{targetId})
	RemoveFriend(ctx context.Context, request RemoveFriendRequestObject) (RemoveFriendResponseObject, error)
	// Get the hypercube status for a player. Should only be used to display in-depth info. Use spicedb for checking related permissions
	// (GET /players/{playerId}/hypercube)
	GetPlayerHypercube(ctx context.Context, request GetPlayerHypercubeRequestObject) (GetPlayerHypercubeResponseObject, error)
	// Remove TOTP setup for a player
	// (DELETE /players/{playerId}/totp)
	RemoveTotp(ctx context.Context, request RemoveTotpRequestObject) (RemoveTotpResponseObject, error)
	// Verify a TOTP code for a player
	// (GET /players/{playerId}/totp)
	CheckTotp(ctx context.Context, request CheckTotpRequestObject) (CheckTotpResponseObject, error)
	// Complete TOTP setup for a player. Must have previously called beginTotpSetup.
	// (PATCH /players/{playerId}/totp/setup)
	CompleteTotpSetup(ctx context.Context, request CompleteTotpSetupRequestObject) (CompleteTotpSetupResponseObject, error)
	// Begin TOTP setup for a player. Overwrites any previous in progress attempt
	// (POST /players/{playerId}/totp/setup)
	BeginTotpSetup(ctx context.Context, request BeginTotpSetupRequestObject) (BeginTotpSetupResponseObject, error)
	// Buy a named upgrade for the given price
	// (POST /players/{playerId}/upgrades)
	BuyNamedUpgrade(ctx context.Context, request BuyNamedUpgradeRequestObject) (BuyNamedUpgradeResponseObject, error)
	// Get punishments
	// (GET /punishments)
	GetPunishments(ctx context.Context, request GetPunishmentsRequestObject) (GetPunishmentsResponseObject, error)
	// Create a new punishment
	// (POST /punishments)
	CreatePunishment(ctx context.Context, request CreatePunishmentRequestObject) (CreatePunishmentResponseObject, error)
	// Get punishment ladders
	// (GET /punishments/ladders)
	GetPunishmentLadders(ctx context.Context, request GetPunishmentLaddersRequestObject) (GetPunishmentLaddersResponseObject, error)
	// Get a punishment ladder entry
	// (GET /punishments/ladders/entry)
	GetPunishmentLadderEntry(ctx context.Context, request GetPunishmentLadderEntryRequestObject) (GetPunishmentLadderEntryResponseObject, error)
	// Revoke the latest punishment for a player
	// (POST /punishments/revoke)
	RevokePunishment(ctx context.Context, request RevokePunishmentRequestObject) (RevokePunishmentResponseObject, error)
	// Get the active punishment for a player
	// (GET /punishments/{playerId}/active)
	GetActivePunishment(ctx context.Context, request GetActivePunishmentRequestObject) (GetActivePunishmentResponseObject, error)
	// Get the recap data for a player
	// (GET /recap/{playerId}/{year})
	GetPlayerRecap(ctx context.Context, request GetPlayerRecapRequestObject) (GetPlayerRecapResponseObject, error)
	// Generic player "completion" API. Used for completing player names or IDs.
	// (POST /tab_complete)
	PerformTabComplete(ctx context.Context, request PerformTabCompleteRequestObject) (PerformTabCompleteResponseObject, error)
	// Create a Tebex checkout link for the given player & package
	// (POST /tebex/checkout)
	TebexCheckout(ctx context.Context, request TebexCheckoutRequestObject) (TebexCheckoutResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

// Faucet operation middleware
func (sh *strictHandler) Faucet(w http.ResponseWriter, r *http.Request) {
	var request FaucetRequestObject

	var body FaucetJSONRequestBody
	if err := json.NewDecoder(r.Body).Decode(&body); err != nil {
		sh.options.RequestErrorHandlerFunc(w, r, fmt.Errorf("can't decode JSON body: %w", err))
		return
	}
	request.Body = &body

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.Faucet(ctx, request.(FaucetRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "Faucet")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(FaucetResponseObject); ok {
		if err := validResponse.VisitFaucetResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

// CreatePlayerData operation middleware
